def subdomainVisits(cpdomains):
    counts = {}
    for cp in cpdomains:
        count, domain = cp.split()
        count = int(count)
        frags = domain.split('.')
        for i in range(len(frags)):
            sub = '.'.join(frags[i:])
            counts[sub] = counts.get(sub, 0) + count
    return [f"{v} {k}" for k, v in counts.items()]

